14	static inline int select_decode_num_splits(int batch_nheads_mblocks,
15	                                           int num_sms, int num_n_blocks,
16	                                           int max_splits, int active_rows) {
17	  if (batch_nheads_mblocks >=
18	      static_cast<int>(0.8f * static_cast<float>(num_sms))) {
19	    return 1;
20	  }
21	
22	  max_splits = min(max_splits, min(num_sms, num_n_blocks));
23	  if (max_splits <= 1) {
24	    return 1;
25	  }
26	
27	  std::vector<float> efficiency(max_splits, 0.0f);
28	  float max_efficiency = 0.0f;
29	  int max_efficiency_split = 1;
30	  auto is_split_eligible = [num_n_blocks](int num_splits) {
31	    return num_splits == 1 || utils::div_ceil(num_n_blocks, num_splits) !=
32	                                  utils::div_ceil(num_n_blocks, num_splits - 1);
33	  };
34	
35	  for (int num_splits = 1; num_splits <= max_splits; ++num_splits) {
36	    if (!is_split_eligible(num_splits)) {
37	      continue;
38	    }
39	    const float n_waves =
40	        static_cast<float>(batch_nheads_mblocks * num_splits) /
41	        static_cast<float>(num_sms);
42	    const float eff = n_waves / ceilf(n_waves);
43	    efficiency[num_splits - 1] = eff;
44	    if (eff > max_efficiency) {
45	      max_efficiency = eff;
46	      max_efficiency_split = num_splits;
47	    }
48	  }
49	
50	  if (active_rows == 1) {
51	    return max_efficiency_split;
52	  }
53	
54	  for (int num_splits = 1; num_splits <= max_splits; ++num_splits) {
55	    if (!is_split_eligible(num_splits)) {
56	      continue;
57	    }
58	    if (efficiency[num_splits - 1] >= 0.85f * max_efficiency) {
59	      return num_splits;
60	    }
61	  }
62	
63	  return 1;
64	}
