217	template <const int Br, const int Bc, const int kMmaAtomM, const int kMmaAtomN,
218	          const int kMmaAtomK, const int kHeadDim, const int kShareSmemQKV,
219	          const int kPersistQg2s, const int kPersistQs2r, const int kStageQK,
220	          const int kStagePV, const int kPadQ, const int kPadK, const int kPadV>
221	static constexpr int getConfigQKVSmemMaxSize() {
222	#ifdef ENABLE_FFPA_PERSIST_KV_G2S
223	  if constexpr (kHeadDim <=
224	                kMaxDForSmallDKernel) {  // e.g > 128 will use large d kernel
225	    // Calculate SRAM size needed per block, Q,K,V smem size, V shared the QK
226	    // smem.
227	    constexpr int Q_smem_size =
228	        ((kHeadDim / kMmaAtomK) * (Br * (kMmaAtomK + kPadQ)));
229	    constexpr int K_smem_size =
230	        ((kHeadDim / kMmaAtomK) * (Bc * (kMmaAtomK + kPadK)));
231	    constexpr int V_smem_size =
232	        ((kHeadDim / (kMmaAtomN * 2)) * (Bc * (kMmaAtomN * 2 + kPadV)));
233	    constexpr int kQSmemMaxSize = Q_smem_size * 2;
234	    constexpr int kKSmemMaxSize = K_smem_size * 2;
235	    constexpr int kVSmemMaxSize = V_smem_size * 2;
236	    constexpr int kQKSmemMaxSize =
237	        (kQSmemMaxSize > kKSmemMaxSize ? kQSmemMaxSize : kKSmemMaxSize);
238	    constexpr int kQKVSmemMaxSize =
239	        ((kShareSmemQKV && kPersistQs2r) ? (kQKSmemMaxSize + kVSmemMaxSize)
240	                                         :  // QK shared the same smem
241	             (kQSmemMaxSize + kKSmemMaxSize + kVSmemMaxSize));
242	    return kQKVSmemMaxSize;
243	  } else {
244	    // Calculate SRAM size needed per block, Q,K,V smem size, V shared the QK
245	    // smem.
246	    constexpr int Q_smem_size =
247	        ((kPersistQg2s ? (kHeadDim / kMmaAtomK) : kStageQK) *
248	         (Br * (kMmaAtomK + kPadQ))) *
249	        2;
250	    constexpr int K_smem_size = ((kStageQK) * (Bc * (kMmaAtomK + kPadK))) * 2;
251	    constexpr int V_smem_size = (kStagePV * (Bc * (kMmaAtomN * 2 + kPadV))) * 2;
252	    constexpr int kQKSmemMaxSize = (Q_smem_size + K_smem_size);
253	    constexpr int kVSmemMaxSize = V_smem_size;
254	    // try to let V reuse all Q+K smem after Q@K^T, reduce smem usage.
255	    constexpr int kQKVSmemMaxSize =
256	        ((kShareSmemQKV && (!kPersistQg2s))
257	             ? ((kQKSmemMaxSize > kVSmemMaxSize) ? kQKSmemMaxSize
258	                                                 : kVSmemMaxSize)
259	             : (kQKSmemMaxSize + kVSmemMaxSize));
260	    // NOTE: R_D registers usage, s=2, d=64, 16 regs; d=128, 32 regs;
261	    // d=256, 64 regs; d=512, 128 regs; d=1024, 256 regs;
262	    return kQKVSmemMaxSize;
263	  }
264	#else
265	  // Calculate SRAM size needed per block, Q,K,V smem size, V shared the QK
266	  // smem.
267	  constexpr int Q_smem_size =
268	      ((kPersistQg2s ? (kHeadDim / kMmaAtomK) : kStageQK) *
269	       (Br * (kMmaAtomK + kPadQ))) *
270	      2;
271	  constexpr int K_smem_size = ((kStageQK) * (Bc * (kMmaAtomK + kPadK))) * 2;
272	  constexpr int V_smem_size = (kStagePV * (Bc * (kMmaAtomN * 2 + kPadV))) * 2;
273	  constexpr int kQKSmemMaxSize = (Q_smem_size + K_smem_size);
274	  constexpr int kVSmemMaxSize = V_smem_size;
275	  // try to let V reuse all Q+K smem after Q@K^T, reduce smem usage.
276	  constexpr int kQKVSmemMaxSize =
277	      ((kShareSmemQKV && (!kPersistQg2s))
278	           ? ((kQKSmemMaxSize > kVSmemMaxSize) ? kQKSmemMaxSize : kVSmemMaxSize)
279	           : (kQKSmemMaxSize + kVSmemMaxSize));
280	  // NOTE: R_D registers usage, s=2, d=64, 16 regs; d=128, 32 regs;
281	  // d=256, 64 regs; d=512, 128 regs; d=1024, 256 regs;
282	  return kQKVSmemMaxSize;
283	#endif
284	}
